mapper.select:
select a.id, a.account, a.accid, b.realness, a.status, a.deptid, c.fullname, a.createTime, a.modifyTime, a.version, b.video, b.address, b.lat, b.lng, d.name,b.topFlag,b.thumbnail_url as thumbnailUrl from biz_push_record a inner join biz_accident b on a.accid = b.id inner join sys_dept c on a.deptid = c.id left join sys_user d on a.account = d.account and d.status != 3 where 1 = 1
and a.account = #{account}
and b.realness = #{realness} order by a.createtime DESC,b.topFlag DESC

select t2.lat,t2.lng from biz_push_record t1 left join biz_accident t2 on t1.accid = t2.id where t2.realness = -1
and t1.account = #{account}
and t1.createTime >= date_sub(curdate(),interval 3 day)

select t2.lat,t2.lng from biz_push_record t1 left join biz_accident t2 on t1.accid = t2.id where t2.realness != -1
and t1.account = #{account}
and t1.createTime >= date_sub(curdate(),interval 7 day)

select a.id, a.account, a.accid,b.lng2,b.lat2,b.accImg,b.realImg,b.realaddress, b.realness, a.status, a.deptid, c.fullname, a.createTime, a.modifyTime, a.version, b.video, b.address, b.lat, b.lng, d.name ,bwu.phone as linkphone,b.topFlag from biz_push_record a inner join biz_accident b on a.accid = b.id inner join sys_dept c on a.deptid = c.id left join sys_user d on a.account = d.account and d.status != 3 left join biz_wx_user bwu on b.openid=bwu.openid where 1 = 1
and a.account = #{account}
and b.id = #{accid}
order by a.createtime DESC
